arguments.file_text:
@page "/chat"
@layout ChatLayout
@rendermode InteractiveServer
@using sv_529cdb209167430688312ba968e0b4dd.Services
@inject IChatService ChatService

<PageTitle>Chat</PageTitle>

<div class="chat-container">
    @* ── Left Sidebar: Channel List ── *@
    <aside class="channel-sidebar">
        <div class="sidebar-header">
            <h3>Channels</h3>
        </div>
        <ul class="channel-list">
            @if (_channels is not null)
            {
                @foreach (var channel in _channels)
                {
                    <li class="channel-item @(channel.Id == _activeChannelId ? "active" : "")"
                        @onclick="() => SelectChannelAsync(channel)">
                        <div class="channel-name"># @channel.Name</div>
                        <div class="channel-desc">@TruncateDescription(channel.Description)</div>
                        @if (channel.UnreadCount > 0)
                        {
                            <span class="unread-badge">@channel.UnreadCount</span>
                        }
                    </li>
                }
            }
        </ul>
    </aside>

    @* ── Main Message Area ── *@
    <section class="message-area @(_threadOpen ? "" : "expanded")">
        @if (_activeChannel is not null)
        {
            <div class="message-header">
                <h2># @_activeChannel.Name</h2>
                <p>@_activeChannel.Description</p>
            </div>

            <div class="message-list" @onscroll="OnMessageListScroll" @ref="_messageListRef">
                @if (_loadingOlder)
                {
                    <div class="loading-indicator">Loading older messages…</div>
                }
                @if (_messages is not null)
                {
                    @foreach (var msg in _messages)
                    {
                        <div class="message-bubble" @onmouseenter="() => _hoveredMessageId = msg.Id"
                             @onmouseleave="() => _hoveredMessageId = null">
                            <div class="message-meta">
                                <span class="author">@msg.Author</span>
                                <span class="timestamp">@FormatRelativeTime(msg.SentAt)</span>
                            </div>
                            <div class="message-content">@msg.Content</div>

                            @* Reactions *@
                            @if (msg.Reactions.Count > 0)
                            {
                                <div class="reaction-row">
                                    @foreach (var reaction in msg.Reactions)
                                    {
                                        <button class="reaction-badge" title="@string.Join(", ", reaction.Users)"
                                                @onclick="() => AddReactionAsync(msg.Id, reaction.Emoji)">
                                            @reaction.Emoji @reaction.Users.Count
                                        </button>
                                    }
                                </div>
                            }

                            @* Thread replies link *@
                            @if (_threadSummaries.TryGetValue(msg.Id, out var summary))
                            {
                                <button class="thread-link" @onclick="() => OpenThreadAsync(msg)">
                                    @summary.ReplyCount @(summary.ReplyCount == 1 ? "reply" : "replies")
                                    — last @FormatRelativeTime(summary.LastReplyAt)
                                </button>
                            }

                            @* Hover actions *@
                            @if (_hoveredMessageId == msg.Id)
                            {
                                <div class="message-actions">
                                    <button class="action-btn" @onclick="() => OpenThreadAsync(msg)" title="Reply in thread">
                                        💬 Reply
                                    </button>
                                    <button class="action-btn" @onclick="() => ToggleEmojiPicker(msg.Id)" title="Add reaction">
                                        😀 React
                                    </button>
                                </div>

                                @if (_emojiPickerMessageId == msg.Id)
                                {
                                    <div class="emoji-picker">
                                        @foreach (var emoji in _commonEmojis)
                                        {
                                            <button class="emoji-btn" @onclick="() => AddReactionAsync(msg.Id, emoji)">
                                                @emoji
                                            </button>
                                        }
                                    </div>
                                }
                            }
                        </div>
                    }
                }
            </div>

            @* Message input *@
            <div class="message-input-area">
                <textarea @bind="_newMessage" @bind:event="oninput"
                          placeholder="Type a message…"
                          @onkeydown="OnMessageKeyDown" rows="2"></textarea>
                <button class="send-btn" @onclick="SendMessageAsync" disabled="@string.IsNullOrWhiteSpace(_newMessage)">
                    Send
                </button>
            </div>
        }
        else
        {
            <div class="no-channel-selected">
                <p>Select a channel to start chatting</p>
            </div>
        }
    </section>

    @* ── Right Panel: Thread View ── *@
    @if (_threadOpen && _threadRootMessage is not null)
    {
        <aside class="thread-panel">
            <div class="thread-header">
                <h3>Thread</h3>
                <button class="close-btn" @onclick="CloseThread" title="Close thread">✕</button>
            </div>

            <div class="thread-root-quote">
                <span class="author">@_threadRootMessage.Author</span>
                <p>@_threadRootMessage.Content</p>
            </div>

            <div class="thread-messages">
                @if (_threadReplies is not null)
                {
                    @foreach (var reply in _threadReplies)
                    {
                        <div class="message-bubble">
                            <div class="message-meta">
                                <span class="author">@reply.Author</span>
                                <span class="timestamp">@FormatRelativeTime(reply.SentAt)</span>
                            </div>
                            <div class="message-content">@reply.Content</div>

                            @if (reply.Reactions.Count > 0)
                            {
                                <div class="reaction-row">
                                    @foreach (var reaction in reply.Reactions)
                                    {
                                        <button class="reaction-badge" title="@string.Join(", ", reaction.Users)"
                                                @onclick="() => AddReactionAsync(reply.Id, reaction.Emoji)">
                                            @reaction.Emoji @reaction.Users.Count
                                        </button>
                                    }
                                </div>
                            }
                        </div>
                    }
                }
            </div>

            <div class="message-input-area">
                <textarea @bind="_threadReplyText" @bind:event="oninput"
                          placeholder="Reply in thread…"
                          @onkeydown="OnThreadReplyKeyDown" rows="2"></textarea>
                <button class="send-btn" @onclick="SendThreadReplyAsync"
                        disabled="@string.IsNullOrWhiteSpace(_threadReplyText)">
                    Reply
                </button>
            </div>
        </aside>
    }
</div>

@code {
    private const int PageSize = 30;

    private List<Channel>? _channels;
    private int? _activeChannelId;
    private Channel? _activeChannel;

    private List<Message>? _messages;
    private int _messageSkip;
    private bool _loadingOlder;
    private bool _allOlderLoaded;

    private string _newMessage = string.Empty;

    // Thread state
    private bool _threadOpen;
    private Message? _threadRootMessage;
    private List<Message>? _threadReplies;
    private string _threadReplyText = string.Empty;

    // Hover/emoji state
    private int? _hoveredMessageId;
    private int? _emojiPickerMessageId;
    private readonly string[] _commonEmojis = ["👍", "❤️", "😂", "🎉", "🚀", "👀"];

    // Thread summaries keyed by root message id
    private Dictionary<int, ThreadSummary> _threadSummaries = new();

    private ElementReference _messageListRef;

    protected override async Task OnInitializedAsync()
    {
        _channels = await ChatService.GetChannelsAsync();

        if (_channels.Count > 0)
        {
            await SelectChannelAsync(_channels[0]);
        }
    }

    private async Task SelectChannelAsync(Channel channel)
    {
        if (_activeChannelId == channel.Id) return;

        _activeChannelId = channel.Id;
        _activeChannel = channel;
        _messageSkip = 0;
        _allOlderLoaded = false;
        _messages = await ChatService.GetMessagesAsync(channel.Id, 0, PageSize);
        _messageSkip = _messages.Count;

        BuildThreadSummaries();

        await ChatService.MarkChannelReadAsync(channel.Id);

        // Refresh channel list to reflect updated unread counts
        _channels = await ChatService.GetChannelsAsync();
    }

    private void BuildThreadSummaries()
    {
        _threadSummaries.Clear();
        if (_messages is null) return;

        var rootIds = _messages
            .Where(m => m.ReplyToId is not null)
            .Select(m => m.ReplyToId!.Value)
            .Distinct();

        foreach (var rootId in rootIds)
        {
            var replies = _messages.Where(m => m.ReplyToId == rootId).ToList();
            _threadSummaries[rootId] = new ThreadSummary(
                rootId,
                replies.Count,
                replies.Max(r => r.SentAt));
        }
    }

    private async Task OnMessageListScroll()
    {
        // Scroll-to-top pagination is handled via JS interop in production;
        // here we expose a manual trigger. When integrated with JS, call
        // LoadOlderMessagesAsync when scrollTop ≈ 0.
    }

    private async Task LoadOlderMessagesAsync()
    {
        if (_loadingOlder || _allOlderLoaded || _activeChannelId is null) return;

        _loadingOlder = true;
        StateHasChanged();

        var older = await ChatService.GetMessagesAsync(_activeChannelId.Value, _messageSkip, PageSize);

        if (older.Count == 0)
        {
            _allOlderLoaded = true;
        }
        else
        {
            _messages = [..older, ..(_messages ?? [])];
            _messageSkip += older.Count;
            BuildThreadSummaries();
        }

        _loadingOlder = false;
    }

    private async Task SendMessageAsync()
    {
        if (string.IsNullOrWhiteSpace(_newMessage) || _activeChannelId is null) return;

        var sent = await ChatService.SendMessageAsync(_activeChannelId.Value, _newMessage.Trim(), null);
        _messages ??= [];
        _messages.Add(sent);
        _messageSkip++;
        _newMessage = string.Empty;
    }

    private async Task OnMessageKeyDown(KeyboardEventArgs e)
    {
        if (e is { Key: "Enter", ShiftKey: false })
        {
            await SendMessageAsync();
        }
    }

    // ── Thread ──

    private async Task OpenThreadAsync(Message rootMessage)
    {
        _threadRootMessage = rootMessage;
        _threadReplies = await ChatService.GetThreadAsync(rootMessage.Id);
        _threadReplyText = string.Empty;
        _threadOpen = true;
        _emojiPickerMessageId = null;
    }

    private void CloseThread()
    {
        _threadOpen = false;
        _threadRootMessage = null;
        _threadReplies = null;
    }

    private async Task SendThreadReplyAsync()
    {
        if (string.IsNullOrWhiteSpace(_threadReplyText) || _threadRootMessage is null || _activeChannelId is null) return;

        var reply = await ChatService.SendMessageAsync(_activeChannelId.Value, _threadReplyText.Trim(), _threadRootMessage.Id);
        _threadReplies ??= [];
        _threadReplies.Add(reply);
        _threadReplyText = string.Empty;

        // Also add to main list and update summary
        _messages?.Add(reply);
        _messageSkip++;
        BuildThreadSummaries();
    }

    private async Task OnThreadReplyKeyDown(KeyboardEventArgs e)
    {
        if (e is { Key: "Enter", ShiftKey: false })
        {
            await SendThreadReplyAsync();
        }
    }

    // ── Reactions ──

    private async Task AddReactionAsync(int messageId, string emoji)
    {
        await ChatService.AddReactionAsync(messageId, emoji);
        _emojiPickerMessageId = null;

        // Refresh messages to show updated reactions
        if (_activeChannelId is not null)
        {
            _messages = await ChatService.GetMessagesAsync(_activeChannelId.Value, 0, _messageSkip);
            BuildThreadSummaries();
        }

        // Refresh thread if open
        if (_threadOpen && _threadRootMessage is not null)
        {
            _threadReplies = await ChatService.GetThreadAsync(_threadRootMessage.Id);
        }
    }

    private void ToggleEmojiPicker(int messageId)
    {
        _emojiPickerMessageId = _emojiPickerMessageId == messageId ? null : messageId;
    }

    // ── Helpers ──

    private static string FormatRelativeTime(DateTime sentAt)
    {
        var diff = DateTime.UtcNow - sentAt.ToUniversalTime();

        return diff.TotalSeconds switch
        {
            < 60 => "just now",
            < 3600 => $"{(int)diff.TotalMinutes} min ago",
            < 86400 => $"{(int)diff.TotalHours}h ago",
            < 604800 => $"{(int)diff.TotalDays}d ago",
            _ => sentAt.ToString("MMM d, yyyy")
        };
    }

    private static string TruncateDescription(string description)
    {
        return description.Length <= 40 ? description : string.Concat(description.AsSpan(0, 37), "...");
    }
}

