/* ── Chat Page Layout ── */

.chat-container {
    display: flex;
    height: 100vh;
    overflow: hidden;
    font-family: -apple-system, BlinkMacSystemFont, "Segoe UI", Roboto, Helvetica, Arial, sans-serif;
    background: #1a1d21;
    color: #d1d2d3;
}

/* ── Left Sidebar ── */

.channel-sidebar {
    width: 20%;
    min-width: 200px;
    background: #19171d;
    border-right: 1px solid #2c2d30;
    display: flex;
    flex-direction: column;
    overflow: hidden;
}

.sidebar-header {
    padding: 16px 16px 12px;
    border-bottom: 1px solid #2c2d30;
}

    .sidebar-header h3 {
        margin: 0;
        font-size: 1.1rem;
        font-weight: 700;
        color: #fff;
    }

.channel-list {
    list-style: none;
    margin: 0;
    padding: 8px 0;
    overflow-y: auto;
    flex: 1;
}

.channel-item {
    padding: 8px 16px;
    cursor: pointer;
    position: relative;
    border-radius: 6px;
    margin: 1px 8px;
    transition: background 0.15s;
}

    .channel-item:hover {
        background: #27242c;
    }

    .channel-item.active {
        background: #1264a3;
        color: #fff;
    }

        .channel-item.active .channel-desc {
            color: rgba(255, 255, 255, 0.7);
        }

.channel-name {
    font-size: 0.95rem;
    font-weight: 600;
    white-space: nowrap;
    overflow: hidden;
    text-overflow: ellipsis;
}

.channel-desc {
    font-size: 0.75rem;
    color: #9a9b9e;
    white-space: nowrap;
    overflow: hidden;
    text-overflow: ellipsis;
    margin-top: 2px;
}

.unread-badge {
    position: absolute;
    right: 12px;
    top: 50%;
    transform: translateY(-50%);
    background: #e01e5a;
    color: #fff;
    font-size: 0.7rem;
    font-weight: 700;
    padding: 2px 7px;
    border-radius: 10px;
    min-width: 18px;
    text-align: center;
}

/* ── Main Message Area ── */

.message-area {
    width: 55%;
    display: flex;
    flex-direction: column;
    background: #1a1d21;
    transition: width 0.2s ease;
    overflow: hidden;
}

    .message-area.expanded {
        width: 80%;
    }

.message-header {
    padding: 14px 20px;
    border-bottom: 1px solid #2c2d30;
    flex-shrink: 0;
}

    .message-header h2 {
        margin: 0;
        font-size: 1.15rem;
        font-weight: 700;
        color: #fff;
    }

    .message-header p {
        margin: 4px 0 0;
        font-size: 0.82rem;
        color: #9a9b9e;
    }

.message-list {
    flex: 1;
    overflow-y: auto;
    padding: 12px 20px;
}

.loading-indicator {
    text-align: center;
    padding: 10px;
    color: #9a9b9e;
    font-size: 0.85rem;
}

.no-channel-selected {
    flex: 1;
    display: flex;
    align-items: center;
    justify-content: center;
    color: #9a9b9e;
    font-size: 1.1rem;
}

/* ── Message Bubble ── */

.message-bubble {
    position: relative;
    padding: 8px 12px;
    border-radius: 6px;
    margin-bottom: 4px;
    transition: background 0.1s;
}

    .message-bubble:hover {
        background: #222529;
    }

.message-meta {
    display: flex;
    align-items: baseline;
    gap: 8px;
    margin-bottom: 2px;
}

.author {
    font-weight: 700;
    font-size: 0.9rem;
    color: #fff;
}

.timestamp {
    font-size: 0.75rem;
    color: #717274;
}

.message-content {
    font-size: 0.92rem;
    line-height: 1.5;
    word-break: break-word;
}

/* ── Reactions ── */

.reaction-row {
    display: flex;
    flex-wrap: wrap;
    gap: 4px;
    margin-top: 6px;
}

.reaction-badge {
    background: #2c2d30;
    border: 1px solid #3a3b3d;
    border-radius: 12px;
    padding: 2px 8px;
    font-size: 0.8rem;
    cursor: pointer;
    color: #d1d2d3;
    transition: background 0.15s;
}

    .reaction-badge:hover {
        background: #3a3b3d;
        border-color: #4a8cc9;
    }

/* ── Thread Link ── */

.thread-link {
    background: none;
    border: none;
    color: #1d9bd1;
    font-size: 0.8rem;
    cursor: pointer;
    padding: 4px 0 0;
    font-weight: 600;
}

    .thread-link:hover {
        text-decoration: underline;
    }

/* ── Hover Actions ── */

.message-actions {
    position: absolute;
    top: -10px;
    right: 12px;
    display: flex;
    gap: 2px;
    background: #1a1d21;
    border: 1px solid #3a3b3d;
    border-radius: 6px;
    padding: 2px;
    box-shadow: 0 2px 8px rgba(0, 0, 0, 0.3);
    z-index: 10;
}

.action-btn {
    background: none;
    border: none;
    color: #d1d2d3;
    font-size: 0.8rem;
    padding: 4px 8px;
    cursor: pointer;
    border-radius: 4px;
    white-space: nowrap;
}

